import React, { useState, useEffect } from 'react';
import type { Place, Analytics } from '../types';
import Button from '../components/Button';
import ReviewSystem from '../components/ReviewSystem';
import { analyticsService } from '../services/analyticsService';
import { notificationService } from '../lib/appwriteService';
// REMOVED: BookingConfirmationPopup - using original booking system

interface PlaceDetailPageProps {
    place: Place;
    onBack: () => void;
    onBook: (place: Place) => void;
    onQuickBookWithChat?: (place: Place) => void; // Quick book with chat
    onIncrementAnalytics: (metric: keyof Analytics) => void;
    onShowRegisterPrompt?: () => void; // Show registration popup
    isCustomerLoggedIn?: boolean; // Check if customer is logged in
    t: any;
    loggedInProviderId?: number | string; // To prevent self-notification
    agentCode?: string; // Optional agent attribution for sharing
    // Villa portal handlers (optional)
    onVillaPortalClick?: () => void;
    onAgentPortalClick?: () => void;
}

const WhatsAppIcon: React.FC<{className?: string}> = ({ className }) => (
    <svg className={className} viewBox="0 0 24 24" fill="currentColor">
        <path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.587-5.946.003-6.556 5.338-11.891 11.893-11.891 3.181.001 6.167 1.24 8.413 3.488 2.245 2.248 3.481 5.236 3.48 8.414-.003 6.557-5.338 11.892-11.894 11.892-1.99 0-3.903-.52-5.614-1.486L.057 24zM6.591 17.419c.404.652.812 1.272 1.242 1.85 1.58 2.116 3.663 3.22 5.953 3.218 5.55-.006 10.038-4.488 10.043-10.038.005-5.55-4.488-10.038-10.038-10.043-5.55.005-10.038 4.488-10.043 10.038.002 2.13.642 4.148 1.822 5.898l-1.03 3.766 3.844-1.025z"/>
    </svg>
);


const PlaceDetailPage: React.FC<PlaceDetailPageProps> = ({ 
    place, 
    onBack, 
    // onBook, // Removed - using industry standard booking flow instead
    onQuickBookWithChat,
    onIncrementAnalytics, 
    onShowRegisterPrompt,
    isCustomerLoggedIn = false,
    t, 
    loggedInProviderId,
    agentCode
}) => {
    const [currentMainImage, setCurrentMainImage] = useState(place.mainImage);
    // REMOVED: showBookingConfirmation - using original booking system
    
    // Detect language from translations object
    const currentLanguage: 'en' | 'id' = t?.contactButton === 'Contact' ? 'en' : 'id';

    // Parse JSON strings
    const massageTypes = typeof place.massageTypes === 'string' ? JSON.parse(place.massageTypes) : place.massageTypes;
    const pricing = typeof place.pricing === 'string' ? JSON.parse(place.pricing) : place.pricing;
    
    // Check if place has active discount
    const hasDiscount = place.discountPercentage && place.discountPercentage > 0;
    
    // Calculate discounted prices
    const getDiscountedPrice = (originalPrice: number) => {
        if (hasDiscount) {
            return Math.round(originalPrice * (1 - place.discountPercentage! / 100));
        }
        return originalPrice;
    };

    // Format price for display (adds K suffix)
    const formatPrice = (price: number) => {
        return price.toLocaleString('en-US', {minimumIntegerDigits: 3, useGrouping: false});
    };

    useEffect(() => {
        // Track real analytics
        analyticsService.trackProfileView(
            place.id,
            'place',
            undefined // userId if available
        ).catch(err => console.error('Analytics tracking error:', err));
        
        // Keep legacy tracking for backwards compatibility
        onIncrementAnalytics('views');
    }, [place.id, onIncrementAnalytics]);

    const openWhatsApp = () => {
        // Convert place.id to number for comparison
        const placeIdNumber = typeof place.id === 'string' ? parseInt(place.id) : place.id;

        // Send notification to place ONLY if it's not them clicking their own button
        if (loggedInProviderId !== placeIdNumber) {
            notificationService.createWhatsAppContactNotification({
                userId: String(placeIdNumber),
                providerName: place.name,
                customerName: 'Customer'
            }).catch(err => console.log('Notification failed:', err));
        } else {
            console.log('🔇 Skipping self-notification (you clicked your own button)');
        }

        // Track real analytics
        analyticsService.trackWhatsAppClick(
            place.id,
            'place',
            undefined // userId if available
        ).catch(err => console.error('Analytics tracking error:', err));
        
        // Keep legacy tracking
        onIncrementAnalytics('whatsapp_clicks');
        window.open(`https://wa.me/${place.whatsappNumber}`, '_blank');
    };

    const getStatus = (): { text: string; color: string } => {
        if (!place.openingTime || !place.closingTime) {
            return { text: 'N/A', color: 'bg-gray-500' };
        }
        
        try {
            const now = new Date();
            const currentTime = now.getHours() * 60 + now.getMinutes();

            const [openHour, openMinute] = place.openingTime.split(':').map(Number);
            const openTime = openHour * 60 + openMinute;

            const [closeHour, closeMinute] = place.closingTime.split(':').map(Number);
            const closeTime = closeHour * 60 + closeMinute;

            if (currentTime >= openTime && currentTime <= closeTime) {
                return { text: 'Open', color: 'bg-green-500' };
            }
            return { text: 'Closed', color: 'bg-red-500' };
        } catch (error) {
            console.error("Error parsing time:", error);
            return { text: 'N/A', color: 'bg-gray-500' };
        }
    };

    const status = getStatus();
    
    const handleShare = async () => {
        try {
            const url = new URL(window.location.href);
            if (agentCode) {
                url.searchParams.set('agent', agentCode);
            }
            // Preserve any provider deep link if present; otherwise include a hint
            if (!url.searchParams.get('provider')) {
                url.searchParams.set('provider', `place-${place.id}`);
            }
            const shareUrl = url.toString();

            const shareData = {
                title: `${place.name} – IndaStreet Massage Place`,
                text: `Check out ${place.name} on IndaStreet`,
                url: shareUrl
            } as ShareData;

            if (navigator.share) {
                await navigator.share(shareData);
            } else {
                await navigator.clipboard.writeText(shareUrl);
                alert('Link copied to clipboard');
            }
        } catch {
            // Fallback copy on any error
            try {
                const url = new URL(window.location.href);
                if (agentCode) url.searchParams.set('agent', agentCode);
                if (!url.searchParams.get('provider')) url.searchParams.set('provider', `place-${place.id}`);
                await navigator.clipboard.writeText(url.toString());
                alert('Link copied to clipboard');
            } catch {}
        }
    };
    
    return (
        <div className="min-h-screen bg-white">
             <div className="relative">
                <img className="w-full h-64 object-cover" src={currentMainImage} alt={place.name} />
                <div className="absolute inset-0 bg-black/20"></div>
                <button onClick={onBack} className="absolute top-4 left-4 bg-white/70 rounded-full p-2 text-gray-800 hover:bg-white transition-colors z-10">
                     <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                    </svg>
                </button>
                <button onClick={handleShare} title="Share" className="absolute top-4 left-16 bg-white/70 rounded-full p-2 text-gray-800 hover:bg-white transition-colors z-10">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.367 2.684 3 3 0 00-5.367-2.684z" />
                    </svg>
                </button>
                <span className={`absolute top-4 right-4 px-3 py-1 rounded-full text-white font-bold text-sm ${status.color} z-10 shadow-lg`}>
                    {status.text}
                </span>
            </div>
            
            <div className="p-4 pb-20">
                <div className="grid grid-cols-3 gap-2 mb-4">
                    {place.thumbnailImages.map((img, index) => (
                        <img 
                            key={index} 
                            src={img} 
                            alt={`${place.name} thumbnail ${index+1}`} 
                            className="w-full h-24 object-cover rounded-lg shadow-sm cursor-pointer hover:opacity-80 transition-opacity" 
                            onClick={() => setCurrentMainImage(img)}
                        />
                    ))}
                </div>

                <h1 className="text-3xl font-bold text-gray-900">{place.name}</h1>
                {place.openingTime && place.closingTime && (
                    <p className="text-sm text-gray-500 mt-1 font-medium">
                        Today's Hours: {place.openingTime} - {place.closingTime}
                    </p>
                )}
                <p className="mt-2 text-gray-600">{place.description}</p>
            </div>

            <div className="px-4 py-2">
                <h3 className="text-xl font-semibold text-gray-800 mb-3">Services Offered</h3>
                <div className="flex flex-wrap gap-2">
                    {massageTypes && Array.isArray(massageTypes) && massageTypes.map((type: string) => (
                        <span key={type} className="px-3 py-1 bg-gray-100 text-gray-800 text-sm font-medium rounded-full">{type}</span>
                    ))}
                </div>
            </div>

            <div className="px-4 py-2 mt-4">
                <h3 className="text-xl font-semibold text-gray-800 mb-2">{t.pricingTitle}</h3>
                <div className="grid grid-cols-3 gap-2 text-center text-sm text-gray-600">
                    {/* 60 min pricing */}
                    <div className={`bg-brand-green-light p-3 rounded-lg border border-gray-200 shadow-md relative transition-all duration-500 ${
                        hasDiscount 
                            ? 'shadow-orange-500/60 shadow-xl ring-4 ring-orange-400/40 bg-gradient-to-br from-orange-50 to-orange-100 animate-pulse border-orange-300' 
                            : ''
                    }`}>
                        <p>60 min</p>
                        {hasDiscount ? (
                            <>
                                <p className="font-bold text-lg text-brand-green-dark">
                                    Rp {formatPrice(getDiscountedPrice(Number(pricing[60])))}K
                                </p>
                                <span className="absolute -top-2 -right-2 bg-red-500 text-white text-xs font-bold rounded-full w-10 h-10 flex items-center justify-center shadow-lg animate-bounce">
                                    -{place.discountPercentage}%
                                </span>
                            </>
                        ) : (
                            <p className="font-bold text-lg text-brand-green-dark">
                                Rp {formatPrice(Number(pricing[60]))}K
                            </p>
                        )}
                    </div>
                    
                    {/* 90 min pricing */}
                    <div className={`bg-brand-green-light p-3 rounded-lg border border-gray-200 shadow-md relative transition-all duration-500 ${
                        hasDiscount 
                            ? 'shadow-orange-500/60 shadow-xl ring-4 ring-orange-400/40 bg-gradient-to-br from-orange-50 to-orange-100 animate-pulse border-orange-300' 
                            : ''
                    }`}>
                        <p>90 min</p>
                        {hasDiscount ? (
                            <>
                                <p className="font-bold text-lg text-brand-green-dark">
                                    Rp {formatPrice(getDiscountedPrice(Number(pricing[90])))}K
                                </p>
                                <span className="absolute -top-2 -right-2 bg-red-500 text-white text-xs font-bold rounded-full w-10 h-10 flex items-center justify-center shadow-lg animate-bounce">
                                    -{place.discountPercentage}%
                                </span>
                            </>
                        ) : (
                            <p className="font-bold text-lg text-brand-green-dark">
                                Rp {formatPrice(Number(pricing[90]))}K
                            </p>
                        )}
                    </div>
                    
                    {/* 120 min pricing */}
                    <div className={`bg-brand-green-light p-3 rounded-lg border border-gray-200 shadow-md relative transition-all duration-500 ${
                        hasDiscount 
                            ? 'shadow-orange-500/60 shadow-xl ring-4 ring-orange-400/40 bg-gradient-to-br from-orange-50 to-orange-100 animate-pulse border-orange-300' 
                            : ''
                    }`}>
                        <p>120 min</p>
                        {hasDiscount ? (
                            <>
                                <p className="font-bold text-lg text-brand-green-dark">
                                    Rp {formatPrice(getDiscountedPrice(Number(pricing[120])))}K
                                </p>
                                <span className="absolute -top-2 -right-2 bg-red-500 text-white text-xs font-bold rounded-full w-10 h-10 flex items-center justify-center shadow-lg animate-bounce">
                                    -{place.discountPercentage}%
                                </span>
                            </>
                        ) : (
                            <p className="font-bold text-lg text-brand-green-dark">
                                Rp {formatPrice(Number(pricing[120]))}K
                            </p>
                        )}
                    </div>
                </div>
            </div>

            {/* Review System */}
            <div className="p-4 pb-20">
                <ReviewSystem
                    provider={place}
                    providerType="place"
                    currentUserId={isCustomerLoggedIn ? "customer-123" : undefined} // TODO: Get actual customer ID
                    currentUserName={isCustomerLoggedIn ? "Customer" : undefined} // TODO: Get actual customer name
                    showAddReview={isCustomerLoggedIn}
                />
            </div>

            <div className="p-4 pb-20 mt-4 sticky bottom-0 bg-white border-t flex gap-2">
                 <button
                    onClick={() => {
                        console.log('🟢 WhatsApp button clicked - will play sound');
                        openWhatsApp();
                    }}
                    className="w-1/2 flex items-center justify-center gap-2 bg-green-500 text-white font-bold py-3 px-4 rounded-lg hover:bg-green-600 transition-colors duration-300 shadow-md"
                >
                    <WhatsAppIcon className="w-5 h-5"/>
                    <span>{t.contactButton}</span>
                </button>
                <Button 
                    onClick={() => {
                        console.log('🔵 Book button clicked - using industry standard booking flow');
                        // Industry standard: Show confirmation first, then redirect to chat
                        if (!isCustomerLoggedIn) {
                            onShowRegisterPrompt?.();
                            return;
                        }
                        // Direct chat opening - using original booking system
                        onQuickBookWithChat?.(place);
                    }} 
                    className="w-1/2 shadow-md"
                >
                    📅 {t.bookButton}
                </Button>
            </div>

            {/* REMOVED: BookingConfirmationPopup - using original booking system */}
        </div>
    );
};

export default PlaceDetailPage;

